def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    if wlan.isconnected():
        print("\nWiFi connected!")
        print("IP address:", wlan.ifconfig()[0])
        return wlan.ifconfig()[0]
    else:
        print("\nFailed to connect to WiFi")
        return None


def base64_encode(data):
    return binascii.b2a_base64(data).strip().decode("utf-8")


def compute_websocket_accept(key):
    GUID = "258EAFA5-E914-47DA-95CA-5AB5A06098AD"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode("utf-8")).digest()
    return base64_encode(sha1_hash)


def parse_http_headers(data):
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def websocket_handshake(client_socket):
    try:
        data = client_socket.recv(1024)
        if not data:
            return False

        request_line, headers = parse_http_headers(data)

        if "sec-websocket-key" not in headers:
            # Serve a simple HTML page for browser access
            if "GET / " in request_line or "GET /index" in request_line:
                send_html_page(client_socket)
                return False
            client_socket.send(b"HTTP/1.1 400 Bad Request\r\n\r\n")
            return False

        ws_key = headers["sec-websocket-key"]
        accept_key = compute_websocket_accept(ws_key)

        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: {}\r\n"
            "\r\n"
        ).format(accept_key)

        client_socket.send(response.encode("utf-8"))
        return True

    except Exception as e:
        print("Handshake error:", e)
        return False


